const crypto = require("crypto");

/* =========================
   PLACEHOLDER INPUTS (for testing)
   ========================= */
const PLACEHOLDER_URL = "$input.first().json.url";
const PLACEHOLDER_TITLE = "$input.first().json.title";
const PLACEHOLDER_SUMMARY = "$input.first().json.content";

/* =========================
   HELPERS
   ========================= */
function normalizeWhitespace(input) {
  return String(input || "")
    .replace(/\s+/g, " ")
    .trim();
}

function canonicalUrl(url) {
  try {
    const u = new URL(String(url || "").trim());
    const DROP_PARAMS = new Set([
      "utm_source", "utm_medium", "utm_campaign", "utm_term", "utm_content",
      "fbclid", "gclid", "igshid",
      "mc_cid", "mc_eid",
      "at_medium", "at_campaign", "at_custom1", "at_custom2", "at_custom3"
    ]);
    [...u.searchParams.keys()].forEach(key => {
      if (DROP_PARAMS.has(key.toLowerCase())) u.searchParams.delete(key);
    });
    const sortedParams = [...u.searchParams.entries()].sort(([a], [b]) => a.localeCompare(b));
    u.search = "";
    for (const [k, v] of sortedParams) u.searchParams.append(k, v);
    u.pathname = u.pathname.replace(/\/+$/, "");
    return u.toString();
  } catch {
    return String(url || "").trim();
  }
}

function sha256Hex(input) {
  return crypto.createHash("sha256").update(input, "utf8").digest("hex");
}

/**
 * Parse common UA/RU textual dates (e.g., "15 Січня 2026") into ISO.
 * Returns ISO string (UTC midnight) or null if can't parse.
 */
/**
 * Parse common UA/RU textual and numeric dates.
 * Handles ambiguity between DD/MM and MM/DD by checking against current time.
 */
function parseUaRuDateToISO(raw) {
  if (!raw) return null;

  // 1. Handle Date objects or timestamps immediately
  if (raw instanceof Date && !isNaN(raw.getTime())) return raw.toISOString();
  if (typeof raw === "number") {
    const d = new Date(raw);
    return isNaN(d.getTime()) ? null : d.toISOString();
  }

  let s = String(raw).trim();
  if (!s) return null;

  const now = new Date();

  // 2. Map UA + RU month names (Unambiguous)
  const monthMap = new Map([
    ["січня", 1], ["січень", 1], ["лютого", 2], ["лютий", 2],
    ["березня", 3], ["березень", 3], ["квітня", 4], ["квітень", 4],
    ["травня", 5], ["травень", 5], ["червня", 6], ["червень", 6],
    ["липня", 7], ["липень", 7], ["серпня", 8], ["серпень", 8],
    ["вересня", 9], ["вересень", 9], ["жовтня", 10], ["жовтень", 10],
    ["листопада", 11], ["листопад", 11], ["грудня", 12], ["грудень", 12],
    ["января", 1], ["январь", 1], ["февраля", 2], ["февраль", 2],
    ["марта", 3], ["март", 3], ["апреля", 4], ["апрель", 4],
    ["мая", 5], ["май", 5], ["июня", 6], ["июнь", 6],
    ["июля", 7], ["июль", 7], ["августа", 8], ["август", 8],
    ["сентября", 9], ["сентябрь", 9], ["октября", 10], ["октябрь", 10],
    ["ноября", 11], ["ноябрь", 11], ["декабря", 12], ["декабрь", 12],
  ]);

  const lower = s.toLowerCase().replace(/\u00A0/g, " ").replace(/\bр\.?\b/gi, "").trim();

  // 3. Handle Textual Dates (e.g., "15 Січня 2026") - These are unambiguous
  const m1 = lower.match(/(\d{1,2})\s*[-./]?\s*([a-z\u0400-\u04ff]+)\s*[-./]?\s*(\d{4})(?:\s+(\d{1,2}):(\d{2}))?/i);
  if (m1) {
    const day = parseInt(m1[1], 10);
    const month = monthMap.get(m1[2]);
    const year = parseInt(m1[3], 10);
    if (month) {
      const d = new Date(Date.UTC(year, month - 1, day, m1[4]||0, m1[5]||0));
      return d.toISOString();
    }
  }

  // 4. Handle Ambiguous Numeric Dates (e.g., "12-03-2026")
  const m2 = lower.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{2,4})(?:\s+(\d{1,2}):(\d{2}))?/);
  if (m2) {
    const v1 = parseInt(m2[1], 10);
    const v2 = parseInt(m2[2], 10);
    let year = parseInt(m2[3], 10);
    if (year < 100) year += 2000; // Handle YY format

    const hh = m2[4] ? parseInt(m2[4], 10) : 0;
    const mm = m2[5] ? parseInt(m2[5], 10) : 0;

    // Option A: Day-Month-Year (Standard UA/EU)
    const dateDMY = new Date(Date.UTC(year, v2 - 1, v1, hh, mm));
    // Option B: Month-Day-Year (Standard US)
    const dateMDY = new Date(Date.UTC(year, v1 - 1, v2, hh, mm));

    const isDMYValid = !isNaN(dateDMY.getTime()) && v2 <= 12;
    const isMDYValid = !isNaN(dateMDY.getTime()) && v1 <= 12;

    if (isDMYValid && isMDYValid) {
      // Logic: If one is in the future and the other isn't, pick the one in the past.
      if (dateDMY > now && dateMDY <= now) return dateMDY.toISOString();
      if (dateMDY > now && dateDMY <= now) return dateDMY.toISOString();

      // If both are in the past, default to DMY (most common for your specific sources)
      return dateDMY.toISOString();
    } else if (isDMYValid) {
      return dateDMY.toISOString();
    } else if (isMDYValid) {
      return dateMDY.toISOString();
    }
  }

  // 5. Fallback for ISO strings only (skip for generic numeric strings to avoid US-default bug)
  if (s.includes('T') || s.includes('Z')) {
    const native = new Date(s);
    if (!isNaN(native.getTime())) return native.toISOString();
  }

  return null;
}
/**
 * Pick a candidate date field from the item.
 * Adjust this list to match your scraper output.
 */
function pickRawDate(json) {
  return (
    json.published_at ??
    json.publishedAt ??
    json.date ??
    json.published ??
    json.pubDate ??
    json.created_at ??
    json.createdAt ??
    null
  );
}

/* =========================
   MAIN PROCESSING
   ========================= */
return $input.all().map(item => {
  const json = item.json || {};

  // Prefer an already-attached source_id. If not present, try common nested locations.
  const source_id =
    json.source_id ||
    json.__feed?.source_id ||
    json.__source?.source_id ||
    json.articles?.source_id ||
    "";

  // Optional: preserve stakeholder_id similarly if you use it
  const stakeholder_id =
    json.stakeholder_id ||
    json.__feed?.stakeholder_id ||
    json.__source?.stakeholder_id ||
    json.articles?.stakeholder_id ||
    "";

  // If placeholders are filled, use them; else use actual item data
  const url = PLACEHOLDER_URL !== "$input.first().json.url"
    ? PLACEHOLDER_URL
    : (json.url || json.link || json.source_url || "");

  const title = PLACEHOLDER_TITLE !== "$input.first().json.title"
    ? PLACEHOLDER_TITLE
    : (json.title || json.headline || "");

  const summary = PLACEHOLDER_SUMMARY !== "$input.first().json.content"
    ? PLACEHOLDER_SUMMARY
    : (json.summary || json.content || json.contentSnippet || json.description || "");

  const canonical_url = canonicalUrl(url);
  const normalized_title = normalizeWhitespace(title).toLowerCase();
  const normalized_summary = normalizeWhitespace(summary).toLowerCase();

  // ---- DATE NORMALIZATION ----
  const rawDate = pickRawDate(json);
  const published_at = parseUaRuDateToISO(rawDate); // ISO or null

  // Include source_id so dedupe is source-aware
  const hash_material = [
    "v1",
    source_id || "no_source",
    canonical_url,
    normalized_title,
    normalized_summary
  ].join("|");

  const content_hash = sha256Hex(hash_material);

  return {
    json: {
      ...json,

      // Preserve/promote IDs
      ...(source_id ? { source_id } : {}),
      ...(stakeholder_id ? { stakeholder_id } : {}),

      // Normalize content fields
      url,
      title,
      summary,

      // Normalized timestamp field for Supabase (use this in your insert)
      published_at, // ISO string or null
      // Keep raw date too (optional but useful for debugging)
      raw_published_at: rawDate ?? null,

      // Hashes
      content_hash,
      n8n_content_hash: content_hash
    }
  };
});

// merge URLs
const urls = [...new Set(
  items
    .map(item => item.json.url)
    .filter(Boolean)
)];

return [
  {
    json: {
      p_urls: urls
    }
  }
];

